import{_ as a,o as s,c as n,a2 as r}from"./chunks/framework.7R1OEGYz.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"overview/architecture.md","filePath":"overview/architecture.md"}'),t={name:"overview/architecture.md"};function o(c,e,i,p,l,h){return s(),n("div",null,[...e[0]||(e[0]=[r(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>Suho has three parts. A browser app, a guardian service, and contracts on GIWA Sepolia. The browser holds the keys. The guardian relays and pays gas. The contracts enforce the rules.</p><h2 id="the-pieces" tabindex="-1">The pieces <a class="header-anchor" href="#the-pieces" aria-label="Permalink to &quot;The pieces&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[ Browser: Suho app ]</span></span>
<span class="line"><span>   passkey signatures (WebAuthn, P-256)</span></span>
<span class="line"><span>        │  REST</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>[ Guardian service (Node, viem) ]</span></span>
<span class="line"><span>   holds a relayer key for gas and the code-issuer key. Never a user key.</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>[ GIWA Sepolia ]</span></span>
<span class="line"><span>   normal RPC for writes, Flashblocks RPC for reads and receipts</span></span>
<span class="line"><span>        ├─ OndolAccountV2   the smart account (EIP-7702 + passkeys)</span></span>
<span class="line"><span>        ├─ OndolTransferGuard   verified pass, strangers warn or need a code</span></span>
<span class="line"><span>        ├─ AriseModule   passkey rotation via single-use codes</span></span>
<span class="line"><span>        ├─ SuhoCodeAttester   codes as EAS attestations</span></span>
<span class="line"><span>        └─ Dojang, EAS, UpnameRegistry   GIWA contracts, never mocked</span></span></code></pre></div><h2 id="the-browser-holds-the-keys" tabindex="-1">The browser holds the keys <a class="header-anchor" href="#the-browser-holds-the-keys" aria-label="Permalink to &quot;The browser holds the keys&quot;">​</a></h2><p>A passkey lives in your device credential manager. It signs an assertion over each batch of calls. The app packages the assertion and sends it to the guardian. The app never sends a private key anywhere.</p><p>The account challenge is <code>keccak256(account, chainId, nonce, calls)</code>. A signature works for exactly one account, on one chain, at one nonce, for one batch. A relayer cannot tamper, replay, or redirect a signed batch.</p><h2 id="the-guardian-relays" tabindex="-1">The guardian relays <a class="header-anchor" href="#the-guardian-relays" aria-label="Permalink to &quot;The guardian relays&quot;">​</a></h2><p>The guardian holds a relayer key that pays gas, and the issuer key that mints verification codes. It exposes a small REST surface: onboard, relay, request a code, verify-me, claim-name, status, directory, card, and the issuer portal.</p><p>The guardian never receives key material on any endpoint. A request-body check rejects anything key-shaped before any handler runs.</p><h2 id="the-contracts-enforce" tabindex="-1">The contracts enforce <a class="header-anchor" href="#the-contracts-enforce" aria-label="Permalink to &quot;The contracts enforce&quot;">​</a></h2><p><code>OndolAccountV2</code> verifies the passkey signature on chain through the P256VERIFY precompile before running any call. <code>OndolTransferGuard</code> decides pass, warn, or require a code. <code>AriseModule</code> rotates the passkey only after a purpose-bound code is consumed. <code>SuhoCodeAttester</code> records codes as revocable EAS attestations.</p><p>See <a href="/docs/internals/ondol-account">The Ondol account</a> for the account internals.</p>`,13)])])}const y=a(t,[["render",o]]);export{u as __pageData,y as default};
